from lxml import etree

def process_soap_xml(xml_string):
    """
    Processes SOAP XML requests and extracts the message body.

    Args:
        xml_string: The SOAP XML request string.

    Returns:
        The message body as a string.
    """

    # Parse the SOAP XML document with DTD validation
    parser = etree.XMLParser(dtd_validation=True)
    xml_document = etree.fromstring(xml_string.encode('utf-8'), parser=parser)

    # Extract the SOAP body element
    soap_body = xml_document.find('soap:Body')

    # Return the message body as a string
    return soap_body.text